from elasticsearch import Elasticsearch, helpers
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Connect to Elasticsearch
es = Elasticsearch(["localhost:9200"])

# Index a document
def index_document(index_name, document):
    try:
        es.index(index=index_name, body=document)
        logger.info("Document indexed successfully: %s", document)
    except Exception as e:
        logger.error("Error indexing document: %s", e)

# Search for documents
def search_documents(index_name, query):
    try:
        response = es.search(index=index_name, body={"query": {"match": query}})
        logger.info("Search successful: %s", response)
        return response
    except Exception as e:
        logger.error("Error searching documents: %s", e)
        return None

# Bulk index documents
def bulk_index_documents(index_name, documents):
    try:
        actions = [
            {
                "_index": index_name,
                "_source": doc
            }
            for doc in documents
        ]
        helpers.bulk(es, actions)
        logger.info("Bulk indexing done.")
    except Exception as e:
        logger.error("Error during bulk indexing: %s", e)

# Aggregate logs by field
def aggregate_logs(index_name, field):
    try:
        response = es.search(index=index_name, body={
            "size": 0,
            "aggs": {
                "log_aggregation": {
                    "terms": {
                        "field": field
                    }
                }
            }
        })
        logger.info("Aggregation successful: %s", response)
        return response
    except Exception as e:
        logger.error("Error aggregating logs: %s", e)
        return None

